mapper.select:
SELECT m.*
FROM ts_chat_message m
INNER JOIN ts_chat_session s ON s.id = m.session_id
WHERE s.user_id = #{query.userId}
  AND s.session_status != 0

    AND m.session_id = #{query.sessionId}


    AND m.sender_type = #{query.senderType}


    AND m.message_type = #{query.messageType}


    AND m.generate_status = #{query.generateStatus}


    AND m.reply_to_message_id = #{query.replyToMessageId}


    AND m.content_text LIKE CONCAT('%', #{query.keyword}, '%')


    AND m.created_at >= #{query.createdAtStart}


    AND m.created_at <= #{query.createdAtEnd}

ORDER BY m.created_at DESC, m.id DESC

SELECT COUNT(1)
FROM ts_chat_session
WHERE id = #{sessionId}
  AND user_id = #{userId}
  AND session_status != 0
